const clients = [
  { id: 'client1', name: 'Client 1 Business Name', locationId: 'LOCATION_ID_1', email: 'client1@email.com', phone: '+1XXXXXXXXXX', language: 'en' },
  { id: 'client2', name: 'Client 2 Business Name', locationId: 'LOCATION_ID_2', email: 'client2@email.com', phone: '+1XXXXXXXXXX', language: 'pt' },
  // { id: 'client3', name: '...', locationId: '...', email: '...', phone: '...', language: 'en' },
