  // { id: 'client6', name: '...', locationId: '...', email: '...', phone: '...', language: 'en' },
  // { id: 'client7', name: '...', locationId: '...', email: '...', phone: '...', language: 'en' },
  // { id: 'client8', name: '...', locationId: '...', email: '...', phone: '...', language: 'en' },
  // { id: 'client9', name: '...', locationId: '...', email: '...', phone: '...', language: 'en' },
  // { id: 'client10', name: '...', locationId: '...', email: '...', phone: '...', language: 'en' },
];

return clients.map(c => ({ json: c }));

// Merge GHL data from contacts and opportunities
const client = $('Client List').item.json;
const contactsData = $('GHL — Get New Contacts').item.json;
const oppsData = $('GHL — Get Opportunities').item.json;

const contacts = contactsData.contacts || [];
const opps = oppsData.opportunities || [];

// Count lead sources
const sources = {};
contacts.forEach(c => {
  const src = c.source || c.tags?.[0] || 'Direct';
  sources[src] = (sources[src] || 0) + 1;
});

// Count opportunity statuses
let won = 0, lost = 0, open = 0, value = 0;
opps.forEach(o => {
  if (o.status === 'won') { won++; value += (o.monetaryValue || 0); }
  else if (o.status === 'lost') lost++;
  else open++;
});

const now = new Date();
const thirtyAgo = new Date(now.getTime() - 30*24*60*60*1000);

return [{
  json: {
    ...client,
    period: thirtyAgo.toISOString().split('T')[0] + ' to ' + now.toISOString().split('T')[0],
    totalLeads: contacts.length,
    leadSources: JSON.stringify(sources),
    totalOpps: opps.length,
    oppsWon: won,
    oppsLost: lost,
    oppsOpen: open,
    pipelineValue: value,
    monthName: now.toLocaleString('en-US', { month: 'long', year: 'numeric' })
  }
}];

