const client = $('Merge & Process Data').item.json;
const aiResponse = $json;
const report = aiResponse.choices[0].message.content;
const monthName = client.monthName;

// Build HTML email
const reportHtml = report.replace(/\n/g, '<br>').replace(/\*\*(.*?)\*\*/g, '<b>$1</b>');

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="font-family:Inter,Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;color:#333;">
<div style="background:linear-gradient(135deg,#0d1b2a,#1a237e);padding:30px;border-radius:12px 12px 0 0;text-align:center;">
<h1 style="color:#ffd700;margin:0;font-size:22px;">Galaxy IT & Marketing</h1>
<p style="color:rgba(255,255,255,0.7);margin:8px 0 0;font-size:14px;">Monthly Performance Report — ${monthName}</p>
</div>
<div style="background:#fff;padding:30px;border:1px solid #e5e5e5;border-top:none;">
<p style="font-size:14px;line-height:1.8;">${reportHtml}</p>
</div>
<div style="background:#f5f5f5;padding:20px;border-radius:0 0 12px 12px;text-align:center;border:1px solid #e5e5e5;border-top:none;">
<p style="margin:0;font-size:12px;color:#888;">Questions? <a href="https://galaxyinfo.us/support" style="color:#1a237e;">Visit Help Center</a> or reply to this email.</p>
<p style="margin:8px 0 0;font-size:11px;color:#aaa;">&copy; 2026 Galaxy IT & Marketing · Worcester, MA</p>
</div>
</body></html>`;

// Short version for WhatsApp
let whatsappMsg = report.substring(0, 800);
if (report.length > 800) whatsappMsg += '\n\n...Relatório completo enviado por email.';

return [{ json: { ...client, report, html, whatsappMsg, monthName } }];

